{
var src = inputs.Length > 0 ? inputs[0] : null;
if (src == null)
    return new PixelBuffer(context.TileSize, context.TileSize);

var strength = GetFloat(parameters, "offsetStrength", 0.02f);
var mode = GetChoice(parameters, "mode", "radial");
var angle = GetFloat(parameters, "angle", 0f) * MathF.PI / 180f;
var mixRatio = GetFloat(parameters, "mixRatio", 1f);
var preserveAlpha = GetBool(parameters, "preserveAlpha", true);

var size = context.TileSize;
var result = new PixelBuffer(size, size);
var cx = size * 0.5f;
var cy = size * 0.5f;
var maxOffset = strength * size;

result.ParallelForEachPixel((x, y) =>
{
    float offsetX, offsetY;

    switch (mode)
    {
        case "horizontal":
            offsetX = maxOffset;
            offsetY = 0;
            break;
        case "vertical":
            offsetX = 0;
            offsetY = maxOffset;
            break;
        case "rotation":
            offsetX = MathF.Cos(angle) * maxOffset;
            offsetY = MathF.Sin(angle) * maxOffset;
            break;
        default: // radial
            var dx = x - cx;
            var dy = y - cy;
            var dist = MathF.Sqrt(dx * dx + dy * dy);
            if (dist > 0)
            {
                offsetX = dx / dist * maxOffset;
                offsetY = dy / dist * maxOffset;
            }
            else
            {
                offsetX = maxOffset;
                offsetY = 0;
            }
            break;
    }

    // Sample R, G, B at different offsets
    var rx = (int)(x + offsetX);
    var ry = (int)(y + offsetY);
    var gx = x;
    var gy = y;
    var bx = (int)(x - offsetX);
    var by = (int)(y - offsetY);

    var (rR, rG, rB, _) = src.GetPixelWrapped(rx, ry);
    var (_, gG, _, _) = src.GetPixelWrapped(gx, gy);
    var (bR, bG, bB, _) = src.GetPixelWrapped(bx, by);

    var (origR, origG, origB, origA) = src.GetPixel(x, y);

    var outR = mixRatio >= 0.999f ? rR : origR + (rR - origR) * mixRatio;
    var outG = mixRatio >= 0.999f ? gG : origG + (gG - origG) * mixRatio;
    var outB = mixRatio >= 0.999f ? bB : origB + (bB - origB) * mixRatio;

    result.SetPixel(x, y,
        Math.Clamp(outR, 0f, 1f),
        Math.Clamp(outG, 0f, 1f),
        Math.Clamp(outB, 0f, 1f),
        preserveAlpha ? origA : 1f);
});

return result;
}
